using sv_66563e7e7f3c4f7e9106ed179c0d3c79.Models;

namespace sv_66563e7e7f3c4f7e9106ed179c0d3c79.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "USB-C Cable", Quantity = 300, UnitPrice = 12.49m, Category = "Electronics" },
        new Product { Id = 3, Name = "Cotton T-Shirt", Quantity = 85, UnitPrice = 19.95m, Category = "Clothing" },
        new Product { Id = 4, Name = "Organic Almonds", Quantity = 60, UnitPrice = 8.75m, Category = "Food" },
        new Product { Id = 5, Name = "Notebook Journal", Quantity = 200, UnitPrice = 5.50m, Category = "Other" },
        new Product { Id = 6, Name = "Running Shoes", Quantity = 42, UnitPrice = 89.99m, Category = "Clothing" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();
            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }
}

